package com.hospital.management.validation;import com.hospital.management.model.RoomForm;import java.math.*;import java.util.*;/** Validates room administration input. */public class RoomValidator{private static final Set<String>T=Set.of("GENERAL","SEMI_PRIVATE","PRIVATE","ICU","EMERGENCY","MATERNITY","PEDIATRIC","OTHER"),S=Set.of("ACTIVE","INACTIVE","MAINTENANCE");public ValidationResult validate(RoomForm f){ValidationResult v=new ValidationResult();if(f==null){v.addError("form","Room is required");return v;}String n=f.getRoomNumber()==null?"":f.getRoomNumber().trim();if(!n.matches("[A-Za-z0-9/-]{1,30}"))v.addError("roomNumber","Use 1-30 letters, digits, hyphen or slash");if(f.getRoomType()==null||!T.contains(f.getRoomType().toUpperCase()))v.addError("roomType","Invalid room type");try{int x=Integer.parseInt(f.getFloorNumber());if(x< -5||x>100)v.addError("floorNumber","Floor must be between -5 and 100");}catch(Exception e){v.addError("floorNumber","Enter a valid floor");}if(f.getDepartmentId()!=null&&f.getDepartmentId()<=0)v.addError("departmentId","Invalid department");try{BigDecimal x=new BigDecimal(f.getDailyRate());if(x.signum()<0||x.scale()>2||x.compareTo(new BigDecimal("9999999999.99"))>0)v.addError("dailyRate","Enter a valid non-negative rate");}catch(Exception e){v.addError("dailyRate","Enter a valid rate");}if(f.getStatus()==null||!S.contains(f.getStatus().toUpperCase()))v.addError("status","Invalid status");return v;}}
